void ApplyMigrations(AppDbContext db)
{
    // EF Core 9 disallows Migrate() inside a user-opened transaction.
    // Migrate() manages its own transactions per migration.
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

