using Microsoft.EntityFrameworkCore;

class CosmosContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=...",
            "MyDatabase");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);

            // EF Core 9 changed the default discriminator property from
            // "Discriminator" to "$type". Existing documents still use
            // "Discriminator", so we must explicitly preserve the old name.
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string Category { get; set; } = null!;
}

using Microsoft.EntityFrameworkCore;

class CosmosService
{
    // EF Core 9 removed synchronous Cosmos DB query support.
    // All queries must use async methods (ToListAsync, FirstAsync, etc.).

    async Task<List<Product>> GetProductsByCategoryAsync(CosmosContext db, string category)
    {
        return await db.Products
            .Where(p => p.Category == category)
            .ToListAsync();
    }

    async Task<Product?> FindProductAsync(CosmosContext db, string id)
    {
        return await db.Products
            .FirstOrDefaultAsync(p => p.Id == id);
    }
}

